2	 * WP Engine API Credentials Management
3	 *
4	 * Allows users to store WP Engine API credentials (username/password) for basic auth.
5	 * This is required for backup creation, as the backup endpoint doesn't support OAuth.
6	 */
7	
8	import { McpToolHandler, McpToolResult, NexusServices } from '../../types';
