18	// ---------------------------------------------------------------------------
19	// wpe_set_api_credentials
20	// ---------------------------------------------------------------------------
21	
22	export const setApiCredentialsHandler: McpToolHandler = {
23	  definition: {
24	    name: 'wpe_set_api_credentials',
25	    description: 'Store WP Engine API credentials (username + password) for basic auth endpoints that do not support OAuth. Required for wpe_create_backup — the backup endpoint only accepts basic auth. Credentials are stored encrypted with OS-level encryption (macOS Keychain). Get credentials from my.wpengine.com under Profile and API Access. Only needs to be done once — credentials persist across sessions.',
26	    inputSchema: {
27	      type: 'object',
28	      properties: {
29	        username: {
30	          type: 'string',
31	          description: 'WP Engine API username (found in WP Engine User Portal)'
32	        },
33	        password: {
34	          type: 'string',
35	          description: 'WP Engine API password'
36	        },
37	      },
38	      required: ['username', 'password'],
39	    },
40	    isAvailable: (_services: NexusServices) => true,
41	  },
42	
43	  async execute(args, services: NexusServices): Promise<McpToolResult> {
44	    try {
45	      const username = args.username as string;
46	      const password = args.password as string;
47	
48	      if (!username || !password) {
49	        return error('Both username and password are required.');
50	      }
51	
52	      await services.localServices!.wpeSetApiCredentials(username, password);
53	
54	      return ok(
55	        '✅ WP Engine API credentials stored securely.\n\n' +
56	        'Backup creation will now use basic authentication.\n' +
57	        'To disable: run wpe_clear_api_credentials'
58	      );
59	    } catch (err: any) {
60	      return error(`Failed to store credentials: ${err.message}`);
61	    }
62	  },
63	};
