23	function getLocalConnectionInfo(): LocalConnectionInfo | null {
24	  const dataDir = process.platform === 'win32'
25	    ? path.join(process.env.APPDATA || os.homedir(), 'Local')
26	    : path.join(os.homedir(), 'Library', 'Application Support', 'Local');
27	  const infoFile = path.join(dataDir, 'graphql-connection-info.json');
