35	async function localGql<T>(query: string, timeout = 120000): Promise<T> {
36	  const info = getLocalConnectionInfo();
37	  if (!info) throw new Error('Could not connect to Local. Is Local running?');
38	  const controller = new AbortController();
39	  const id = setTimeout(() => controller.abort(), timeout);
40	  try {
41	    const res = await fetch(info.url, {
42	      method: 'POST',
43	      headers: {
44	        'Content-Type': 'application/json',
45	        'Authorization': `Bearer ${info.authToken}`,
46	      },
47	      body: JSON.stringify({ query }),
48	      signal: controller.signal,
49	    });
50	    const json = await res.json() as { data?: T; errors?: any[] };
51	    if (json.errors?.length) throw new Error(json.errors[0].message);
52	    return json.data as T;
53	  } finally {
54	    clearTimeout(id);
55	  }
56	}
