634	// ---------------------------------------------------------------------------
635	// Shared usage formatting helpers
636	// ---------------------------------------------------------------------------
637	
638	function formatBytes(bytes: number | string | undefined | null): string {
639	  const n = typeof bytes === 'string' ? parseInt(bytes, 10) : (bytes ?? 0);
640	  if (!n || isNaN(n)) return '0 B';
641	  const units = ['B', 'KB', 'MB', 'GB', 'TB'];
642	  const i = Math.floor(Math.log(n) / Math.log(1024));
643	  return `${(n / Math.pow(1024, i)).toFixed(2)} ${units[i]}`;
644	}
645	
646	function formatNum(v: number | string | undefined | null): string {
647	  const n = typeof v === 'string' ? parseInt(v, 10) : (v ?? 0);
648	  if (!n || isNaN(n)) return '0';
649	  return new Intl.NumberFormat('en-US').format(n);
650	}
651	
652	function printUsage(
653	  label: string,
654	  data: any,
655	  opts: { firstDate: string; lastDate: string; cached: boolean; cachedAgeMinutes: number },
656	): void {
657	  const r = data?.metrics_rollup ?? {};
658	  const monthLabel = (() => {
659	    const [y, m] = opts.firstDate.split('-');
660	    return new Date(Number(y), Number(m) - 1, 1).toLocaleString('en-US', { month: 'long', year: 'numeric' });
661	  })();
662	
663	  const line = '─'.repeat(42);
664	  console.log(`\n${label} — ${monthLabel}`);
665	  console.log(line);
666	  console.log(`  Visits (total):    ${formatNum(r.visit_count?.sum)}`);
667	  console.log(`  Billable visits:   ${formatNum(r.billable_visits?.sum)}`);
668	  console.log(`  Bandwidth:         ${formatBytes(r.network_total_bytes?.sum)}`);
669	  console.log(`  File storage:      ${formatBytes(r.storage_file_bytes?.latest?.value)}`);
670	  console.log(`  DB storage:        ${formatBytes(r.storage_database_bytes?.latest?.value)}`);
671	  console.log(line);
672	  console.log(`  Period:  ${opts.firstDate} → ${opts.lastDate}`);
673	  if (opts.cached) {
674	    console.log(`  Cached:  yes (${opts.cachedAgeMinutes}m old)`);
675	  }
676	  console.log('');
677	}
